import React from 'react';
import { crmPricing, pricingLastUpdated } from '../data/crmPricing';

const AboutPage = () => {
  return (
    <section>
      <h2>О проекте</h2>
      <p>
        Этот сервис помогает малому бизнесу выбрать SaaS-CRM на основе взвешенной оценки
        критериев и экономического расчёта внедрения.
      </p>
      <p>
        Архитектура: React (frontend) → Express REST API (backend) → PostgreSQL (хранение данных).
      </p>

      <div className="result-card">
        <h3>Актуальные цены по конфигурациям</h3>
        <p>Дата обновления: {pricingLastUpdated}</p>
        {crmPricing.map((crm) => (
          <div key={crm.crm} className="pricing-block">
            <p>
              <strong>{crm.crm}</strong> — <a href={crm.source} target="_blank" rel="noreferrer">источник</a>
            </p>
            {crm.configs.map((config) => (
              <p key={`${crm.crm}-${config.name}`}>
                {config.name}: {config.price} ₽ {config.period}
                {config.promoPrice ? ` (акция: ${config.promoPrice} ₽)` : ''}
                {config.oldPrice ? ` (старая цена: ${config.oldPrice} ₽)` : ''}
              </p>
            ))}
            {crm.note && <p className="info">{crm.note}</p>}
          </div>
        ))}
      </div>
    </section>
  );
};

export default AboutPage;
